
.row {
  display: flex;
  align-items: center;
  gap: 10px;
}

.row :deep(.bar-row) {
  flex: 1;
}

.controls {
  display: flex;
  gap: 4px;
}

.btn {
  width: 28px;
  height: 26px;
  padding: 0;
  border: 1.5px solid var(--c-soot);
  background: var(--c-mist);
  color: var(--c-ink);
  font-family: inherit;
  font-weight: bold;
  line-height: 1;
  cursor: pointer;
  box-shadow: 2px 2px 0 rgba(26, 31, 28, 0.12);
}

.btn:active:not(:disabled) {
  transform: translate(1px, 1px);
  box-shadow: 1px 1px 0 rgba(26, 31, 28, 0.12);
}

.btn:disabled {
  opacity: 0.45;
  cursor: not-allowed;
  box-shadow: none;
}

.btn:focus-visible {
  outline: 2px dashed var(--c-soot);
  outline-offset: 2px;
}
