
.bar-row {
  display: flex;
  align-items: center;
  gap: 8px;
}

.label {
  width: 36px;
  font-weight: bold;
  font-size: 0.82rem;
}

.track {
  flex: 1;
  height: 10px;
  border: 1.5px solid var(--c-soot);
  background: var(--c-mist);
  position: relative;
  overflow: hidden;
}

.fill {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  border-right: 1.5px solid var(--c-soot);
  transition: width 0.25s ease;
}

.fill.life {
  background: var(--c-safe);
}

.fill.hunger {
  background: #d4a574;
}

.fill.sta {
  background: #7e9abf;
}

.fill.inf {
  background: var(--c-hazard);
}

.value {
  width: 38px;
  text-align: right;
  font-weight: bold;
  font-size: 0.82rem;
}
